function [sys,params,options] = load_model_linearSysDT(name)
% load_model_linearSysDT - loads a predefined linear discrete-time system
% together with its parameter and option structs.
%
% Provides a central loading interface for linearSysDT models used in CORA-
% based workflows. The function can be extended by adding further model names
% and corresponding system definitions.
%
% Syntax:
%    [sys,params,options] = load_model_linearSysDT(name)
%
% Inputs:
%    name - string identifying the model to be loaded
%
% Outputs:
%    sys     - linearSysDT object
%    params  - parameter struct
%    options - option struct
%
% Reference:
%    -

% Authors:       Nico Holzinger
% Written:       16-April-2026
% Last update:   ---
% Last revision: ---

% ------------------------------ BEGIN CODE -------------------------------

    narginchk(1,1);
    
    % Load different models
    switch name

        case "slipEstimationModel_6D"
            [sys,params,options] = aux_load_slipEstimationModel_6D();

        otherwise
            throw(CORAerror('CORA:wrongValue', ...
                'name', 'slipEstimationModel_6D'));
    end
end


